package chisel3.simulator

import chisel3.{Data, RawModule, SimulationTestHarnessInterface}
import chisel3.experimental.inlinetest.{HasTests, SimulatedTest, TestParameters, TestResult}
import firrtl.options.StageUtils.dramaticMessage
import java.nio.file.attribute.BasicFileAttributes
import java.nio.file.{FileSystems, FileVisitResult, FileVisitor, Files, Path, PathMatcher, Paths}
import scala.collection.mutable
import scala.util.{Failure, Success, Try}
import scala.util.control.NoStackTrace
import svsim._

object SimulationOutcome {

  /** A test result, either success or failure. */
  sealed trait Type

  /** Test passed. */
  case object Success extends Type

  /** Test failed somehow. */
  sealed trait Failure extends Type

  /** Test timed out. */
  case class Timeout(n: BigInt) extends Failure

  /** Test failed with an assertion. */
  case class Assertion(simulatorOutput: String) extends Failure

  /** Test signaled failure. */
  case object SignaledFailure extends Failure
}

object Exceptions {

  class AssertionFailed private[simulator] (message: String, val simulatorOutput: String)
      extends RuntimeException(
        dramaticMessage(
          header = Some("One or more assertions failed during Chiselsim simulation"),
          body = message
        )
      )
      with NoStackTrace

  class Timeout private[simulator] (private[simulator] val timesteps: BigInt, message: String)
      extends RuntimeException(
        dramaticMessage(
          header = Some(s"A timeout occurred after $timesteps timesteps"),
          body = message
        )
      )
      with NoStackTrace

  class TestFailed private[simulator]
      extends RuntimeException(
        dramaticMessage(
          header = Some(s"The test finished and signaled failure"),
          body = ""
        )
      )
      with NoStackTrace

  class TestsFailed private[simulator] (
    message:     String,
    val results: Seq[chisel3.experimental.inlinetest.SimulatedTest]
  ) extends RuntimeException(
        dramaticMessage(
          header = Some("One or more tests failed during simulation"),
          body = message
        )
      )
      with NoStackTrace
}

final object Simulator {

  final case class BackendInvocationDigest[T](
    compilationStartTime: Long,
    compilationEndTime:   Long,
    outcome:              BackendInvocationOutcome[T]
  ) {
    def result = outcome match {
      case SimulationDigest(_, _, outcome) => outcome.get
      case CompilationFailed(error)        => throw error
    }
  }
  sealed trait BackendInvocationOutcome[T]
  final case class CompilationFailed[T](error: Throwable) extends BackendInvocationOutcome[T]

  final case class SimulationDigest[T](simulationStartTime: Long, simulationEndTime: Long, outcome: Try[T])
      extends BackendInvocationOutcome[T]
}

trait Simulator[T <: Backend] {

  val backend: T
  def tag:           String
  def workspacePath: String
  def workingDirectoryPrefix = "workdir"
  def customSimulationWorkingDirectory:   Option[String] = None
  def verbose:                            Boolean = false
  def commonCompilationSettings:          CommonCompilationSettings
  def backendSpecificCompilationSettings: backend.CompilationSettings

  /** Post process a simulation log to see if there are any backend-specific failures.
    *
    * @return None if no failures found or Some if they are
    */
  private def postProcessLog(workspace: Workspace): Option[Throwable] = {
    val log =
      Paths.get(workspace.absolutePath, s"${workspace.workingDirectoryPrefix}-${tag}", "simulation-log.txt").toFile
    val lines = scala.io.Source
      .fromFile(log)
      .getLines()
      .zipWithIndex
      .filter { case (line, _) => backend.assertionFailed.matches(line) }
      .toSeq

    Option.when(lines.nonEmpty)(
      new Exceptions.AssertionFailed(
        simulatorOutput = lines.map(_._1).mkString("\n"),
        message = s"""|The following assertion failures were extracted from the log file:
                      |
                      |  lineNo  line
                      |  ${"-" * 76}
                      |${lines.map { case (line, lineNo) => f"$lineNo%8d  $line" }.mkString("\n")}
                      |
                      |For more information, see the complete log file:
                      |
                      |  ${log}""".stripMargin
      )
    )
  }

  /** Simulate a Chisel module with some stimulus
    *
    * @param module a Chisel module to simulate
    * @param chiselOpts command line options to pass to Chisel
    * @param firtoolOpts command line options to pass to firtool
    * @param settings ChiselSim-related settings used for simulation
    * @param body stimulus to apply to the module
    * @param commonSettingsModifications modifications to common compilation
    * settings
    * @param backendSettingsModifications modifications to backend (e.g.,
    * Verilator or VCS) compilation settings
    *
    * @note Take care when passing `chiselOpts`.  The following options are set
    * by default and if you set incompatible options, the simulation will fail.
    */
  final def simulate[T <: RawModule, U](
    module:      => T,
    chiselOpts:  Array[String] = Array.empty,
    firtoolOpts: Array[String] = Array.empty,
    settings:    Settings[T] = Settings.defaultRaw[T]
  )(body: (SimulatedModule[T]) => U)(
    implicit chiselOptsModifications: ChiselOptionsModifications,
    firtoolOptsModifications:         FirtoolOptionsModifications,
    commonSettingsModifications:      svsim.CommonSettingsModifications,
    backendSettingsModifications:     svsim.BackendSettingsModifications
  ): Simulator.BackendInvocationDigest[U] = {
    val workspace = new Workspace(path = workspacePath, workingDirectoryPrefix = workingDirectoryPrefix)
    workspace.reset()
    val instanceChoiceOpts = settings.instanceChoices.toFirtoolOptions
    val elaboratedModule =
      workspace
        .elaborateGeneratedModule(
          () => module,
          args = chiselOptsModifications(chiselOpts).toSeq,
          firtoolArgs = firtoolOptsModifications(firtoolOpts).toSeq ++ instanceChoiceOpts
        )
    _simulate(workspace, elaboratedModule, settings)(body)
  }

  final def simulateTests[T <: RawModule with HasTests, U](
    module:           => T,
    includeTestGlobs: Array[String],
    chiselOpts:       Array[String] = Array.empty,
    firtoolOpts:      Array[String] = Array.empty,
    settings: Settings[RawModule with SimulationTestHarnessInterface] =
      Settings.defaultRaw[RawModule with SimulationTestHarnessInterface]
  )(body: (SimulatedModule[RawModule with SimulationTestHarnessInterface]) => U)(
    implicit chiselOptsModifications: ChiselOptionsModifications,
    firtoolOptsModifications:         FirtoolOptionsModifications,
    commonSettingsModifications:      svsim.CommonSettingsModifications,
    backendSettingsModifications:     svsim.BackendSettingsModifications
  ) = {
    val workspace = new Workspace(path = workspacePath, workingDirectoryPrefix = workingDirectoryPrefix)
    workspace.reset()
    val filesystem = FileSystems.getDefault()
    val instanceChoiceOpts = settings.instanceChoices.toFirtoolOptions
    val results = workspace
      .elaborateAndMakeTestHarnessWorkspaces(
        () => module,
        includeTestGlobs = includeTestGlobs.toSeq,
        args = chiselOptsModifications(chiselOpts).toSeq,
        firtoolArgs = firtoolOptsModifications(firtoolOpts).toSeq ++ instanceChoiceOpts
      )
      .map { case (testWorkspace, elaboratedTest, elaboratedModule) =>
        val digest = _simulate(testWorkspace, elaboratedModule, settings)(body)
        // Try to unpack the result, otherwise figure out what went wrong.
        // TODO: push this down, i.e. all ChiselSim invocations return a SimulationOutcome
        val outcome: SimulationOutcome.Type =
          try {
            digest.result
            SimulationOutcome.Success
          } catch {
            // Simulation ended due to an aserrtion
            case assertion: Exceptions.AssertionFailed => SimulationOutcome.Assertion(assertion.simulatorOutput)
            // Simulation ended because the testharness signaled success=0
            case _: Exceptions.TestFailed => SimulationOutcome.SignaledFailure
            // Simulation timed out
            case to: Exceptions.Timeout => SimulationOutcome.Timeout(to.timesteps)
            // Simulation did not run correctly
            case e: Throwable => throw e
          }
        SimulatedTest(elaboratedTest, outcome)
      }

    val failures = results.filter(!_.success)
    if (failures.nonEmpty) {
      val moduleName = results.head.dutName
      val failedTests = failures.size
      val passedTests = results.size - failedTests
      val failureMessages = failures.map { test =>
        s"  - ${test.testName}: ${test.result.asInstanceOf[TestResult.Failure].message}"
      }
      val aggregatedMessage =
        s"${moduleName} tests: ${passedTests} passed, ${failedTests} failed\nfailures: \n${failureMessages.mkString("\n")}"
      throw new Exceptions.TestsFailed(aggregatedMessage, results)
    }
  }

  private def _simulate[T <: RawModule, U](
    workspace:        Workspace,
    elaboratedModule: ElaboratedModule[T],
    settings:         Settings[T] = Settings.defaultRaw[T]
  )(body: (SimulatedModule[T]) => U)(
    implicit chiselOptsModifications: ChiselOptionsModifications,
    firtoolOptsModifications:         FirtoolOptionsModifications,
    commonSettingsModifications:      svsim.CommonSettingsModifications,
    backendSettingsModifications:     svsim.BackendSettingsModifications
  ): Simulator.BackendInvocationDigest[U] = {
    // Find all the directories that exist under another directory.
    val primarySourcesDirectories = mutable.LinkedHashSet.empty[String]
    class DirectoryFinder extends FileVisitor[Path] {

      override def visitFile(file: Path, attrs: BasicFileAttributes): FileVisitResult = {
        FileVisitResult.CONTINUE
      }

      override def preVisitDirectory(dir: Path, attrs: BasicFileAttributes): FileVisitResult = {
        FileVisitResult.CONTINUE
      }

      override def postVisitDirectory(dir: Path, ioe: java.io.IOException): FileVisitResult = {
        primarySourcesDirectories += dir.toString
        FileVisitResult.CONTINUE
      }

      override def visitFileFailed(file: Path, ioe: java.io.IOException): FileVisitResult = {
        throw ioe
      }

    }
    Files.walkFileTree(Paths.get(workspace.primarySourcesPath), new DirectoryFinder)

    // Collect a list of library names and paths from the environment. These
    // will be used to resolve library names provided by the user. Environment
    // variables take precedence over Java properties.
    def parseLibraryMap(value: Option[String]): Map[String, String] = {
      value
        .getOrElse("")
        .split(":")
        .filter(_.nonEmpty)
        .map { entry =>
          entry.split("=", 2) match {
            case Array(name, path) => name -> path
            case _ =>
              throw new IllegalArgumentException(
                s"Invalid link library mapping `$entry`; expected `<name>=<path>`"
              )
          }
        }
        .toMap
    }
    val libraryMapFromProp = parseLibraryMap(sys.props.get("chiselsim.libraries"))
    val libraryMapFromEnv = parseLibraryMap(sys.env.get("CHISELSIM_LIBS"))
    val libraryMap = libraryMapFromProp ++ libraryMapFromEnv
    val resolvedLibraryPaths = settings.libraries.map { name =>
      libraryMap.getOrElse(
        name,
        throw new NoSuchElementException(
          s"Link library `$name` not found. " +
            "Set the `CHISELSIM_LIBS` environment variable or the " +
            "`chiselsim.libraries` Java property to provide a list of " +
            "`<name>=<path>` mappings separated by `:`. Available libraries: " +
            s"[${libraryMap.keys.mkString(", ")}]"
        )
      )
    }

    val commonCompilationSettingsUpdated = commonSettingsModifications(
      commonCompilationSettings.copy(
        // Append to the include directorires based on what the
        // workspace indicates is the path for primary sources.  This
        // ensures that `` `include `` directives can be resolved.
        includeDirs = Some(
          commonCompilationSettings.includeDirs.getOrElse(Seq.empty) ++ primarySourcesDirectories
        ),
        verilogPreprocessorDefines =
          commonCompilationSettings.verilogPreprocessorDefines ++ settings.preprocessorDefines(elaboratedModule),
        fileFilter = commonCompilationSettings.fileFilter
          .orElse(settings.verilogLayers.shouldIncludeFile(elaboratedModule)),
        directoryFilter = commonCompilationSettings.directoryFilter.orElse(
          settings.verilogLayers.shouldIncludeDirectory(elaboratedModule, workspace.primarySourcesPath)
        ),
        linkLibraryPaths = commonCompilationSettings.linkLibraryPaths ++ resolvedLibraryPaths ++ settings.libraryPaths,
        simulationSettings = commonCompilationSettings.simulationSettings.copy(
          plusArgs = commonCompilationSettings.simulationSettings.plusArgs ++ settings.plusArgs,
          enableWavesAtTimeZero =
            commonCompilationSettings.simulationSettings.enableWavesAtTimeZero || settings.enableWavesAtTimeZero
        )
      )
    )

    workspace.generateAdditionalSources(timescale = commonCompilationSettingsUpdated.defaultTimescale)

    // Compile the design.  Early exit if the compilation fails for any reason.
    val compilationStartTime = System.nanoTime()
    val simulation =
      try {
        workspace
          .compile(backend)(
            tag,
            commonCompilationSettingsUpdated,
            backendSettingsModifications(backendSpecificCompilationSettings).asInstanceOf[backend.CompilationSettings],
            customSimulationWorkingDirectory,
            verbose
          )
      } catch {
        case error: Throwable =>
          return Simulator.BackendInvocationDigest(
            compilationStartTime = compilationStartTime,
            compilationEndTime = System.nanoTime(),
            outcome = Simulator.CompilationFailed(error)
          )
      }
    val compilationEndTime = System.nanoTime()

    // Simulate the compiled design.  After the simulation completes,
    // post-process the log to figure out what happened.  This post-processing
    // occurs in _both_ the success and failure modes for multiple reasons:
    //
    // 1. svsim returns a vague `UnexpectedEndOfMessage` on failure.
    // 2. svsim assumes that simulators will either exit on an assertion failure
    //    or can be compile-time configured to do so.  This is _not_ the case
    //    for VCS as VCS requires runtime configuration to do and svsim
    //    substitutes its own executable which ignores command line arguments.
    //
    // Note: this would be much better to handle with extensions to the FIRRTL
    // ABI which would abstract away these differences.
    val simulationOutcome = Try {
      simulation.runElaboratedModule(
        elaboratedModule = elaboratedModule,
        traceEnabled = commonCompilationSettingsUpdated.simulationSettings.enableWavesAtTimeZero
      ) { (module: SimulatedModule[T]) =>
        val outcome = body(module)
        module.completeSimulation()
        outcome

      }
    }.transform(
      s /*success*/ = { case success =>
        postProcessLog(workspace) match {
          case None        => Success(success)
          case Some(error) => Failure(error)
        }
      },
      f /*failure*/ = { case originalError =>
        postProcessLog(workspace) match {
          case None           => Failure(originalError)
          case Some(newError) => Failure(newError)
        }
      }
    )

    val simulationEndTime = System.nanoTime()

    // Return the simulation result.
    Simulator.BackendInvocationDigest(
      compilationStartTime = compilationStartTime,
      compilationEndTime = compilationEndTime,
      outcome = Simulator.SimulationDigest(
        simulationStartTime = compilationEndTime,
        simulationEndTime = simulationEndTime,
        outcome = simulationOutcome
      )
    )

  }

}

package chisel3

import svsim._
import chisel3.reflect.DataMirror
import chisel3.experimental.dataview.reifyIdentityView
import chisel3.experimental.inlinetest.{ElaboratedTest, HasTests, TestParameters}
import chisel3.stage.DesignAnnotation
import scala.collection.mutable
import java.nio.file.{Files, Path, Paths}
import firrtl.{annoSeqToSeq, seqToAnnoSeq}
import firrtl.AnnotationSeq

package object simulator {

  /** A trait that provides the minimal set of ChiselSim APIs.
    *
    * Example usage:
    * {{{
    * import chisel3.simulator.ChiselSim
    *
    * class Foo extends ChiselSim {
    *   /** This has access to all ChiselSim APIs like `simulate`, `peek`, and `poke`. */
    * }
    * }}}
    *
    * @see [[chisel3.simulator.scalatest.ChiselSim]]
    */
  trait ChiselSim extends ControlAPI with PeekPokeAPI with SimulatorAPI

  /**
    * An opaque class that can be passed to `Simulation.run` to get access to a `SimulatedModule` in the simulation body.
    */
  final class ElaboratedModule[T] private[simulator] (
    private[simulator] val wrapped: T,
    private[simulator] val ports:   Seq[(Data, ModuleInfo.Port)],
    private[simulator] val layers:  Seq[chisel3.layer.Layer]
  ) {

    private[chisel3] val portMap = ports.toMap

  }

  /**
    * A class that enables using a Chisel module to control an `svsim.Simulation`.
    */
  final class SimulatedModule[T] private[simulator] (
    private[simulator] val elaboratedModule: ElaboratedModule[T],
    controller:                              Simulation.Controller
  ) extends AnySimulatedModule(elaboratedModule.ports, controller) {
    def wrapped: T = elaboratedModule.wrapped
  }
  sealed class AnySimulatedModule protected (
    ports:          Seq[(Data, ModuleInfo.Port)],
    val controller: Simulation.Controller
  ) {

    // -- Port Mapping

    private val simulationPorts = ports.map { case (data, port) =>
      data -> controller.port(port.name)
    }.toMap
    def port(data: Data): Simulation.Port = {
      // TODO, we can support non identity views, but it will require changing this API to return a Seq[Port]
      // and packing/unpacking the BigInt literal representation.
      // TODO implement support for read-only.
      val (reified, _) = reifyIdentityView(data).getOrElse {
        val url = "https://github.com/chipsalliance/chisel/issues/new/choose"
        throw new Exception(
          s"Cannot poke $data as is a view that does not map to a single Data. " +
            s"Please file an issue at $url requesting support for this use case."
        )
      }
      simulationPorts(reified)
    }

    // -- Peek/Poke API Support

    // When using the low-level API, the user must explicitly call `controller.completeInFlightCommands()` to ensure that all commands are executed. When using a higher-level API like peek/poke, we handle this automatically.
    private var shouldCompleteInFlightCommands: Boolean = false
    private[simulator] def completeSimulation() = {
      if (shouldCompleteInFlightCommands) {
        shouldCompleteInFlightCommands = false
        controller.completeInFlightCommands()
      }
    }

    // The peek/poke API implicitly evaluates on the first peek after one or more pokes. This is _only_ for peek/poke and using `controller` directly will not provide this behavior.
    private var evaluateBeforeNextPeek: Boolean = false
    private[simulator] def willEvaluate() = {
      evaluateBeforeNextPeek = false
    }
    private[simulator] def willPoke() = {
      shouldCompleteInFlightCommands = true
      evaluateBeforeNextPeek = true
    }
    private[simulator] def willPeek() = {
      shouldCompleteInFlightCommands = true
      if (evaluateBeforeNextPeek) {
        willEvaluate()
        controller.run(0)
      }
    }
  }
  private[simulator] object AnySimulatedModule {
    private val dynamicVariable = new scala.util.DynamicVariable[Option[AnySimulatedModule]](None)
    def withValue[T](module: AnySimulatedModule)(body: => T): T = {
      require(dynamicVariable.value.isEmpty, "Nested simulations are not supported.")
      dynamicVariable.withValue(Some(module))(body)
    }
    def current: AnySimulatedModule = dynamicVariable.value.get
  }

  implicit class ChiselSimulation(simulation: Simulation) {
    def runElaboratedModule[T, U](
      elaboratedModule:              ElaboratedModule[T],
      conservativeCommandResolution: Boolean = false,
      verbose:                       Boolean = false,
      traceEnabled:                  Boolean = false,
      executionScriptLimit:          Option[Int] = None
    )(body: SimulatedModule[T] => U): U = {
      simulation.run(conservativeCommandResolution, verbose, traceEnabled, executionScriptLimit) { controller =>
        val module = new SimulatedModule(elaboratedModule, controller)
        AnySimulatedModule.withValue(module) {
          body(module)
        }
      }
    }
  }

  implicit class ChiselWorkspace(workspace: Workspace) {
    def elaborateGeneratedModule[T <: RawModule](
      generateModule: () => T,
      args:           Seq[String] = Seq.empty,
      firtoolArgs:    Seq[String] = Seq.empty
    ): ElaboratedModule[T] = {
      val generated = generateWorkspaceSources(generateModule, args, firtoolArgs)
      val ports = getModuleInfoPorts(generated.dut)
      val moduleInfo = initializeModuleInfo(generated.dut, ports.map(_._2))
      val layers = generated.outputAnnotations.collectFirst { case DesignAnnotation(_, layers) => layers }.get
      new ElaboratedModule(generated.dut, ports, layers)
    }

    def elaborateAndMakeTestHarnessWorkspaces[T <: RawModule with HasTests](
      generateModule:   () => T,
      includeTestGlobs: Seq[String],
      args:             Seq[String] = Seq.empty,
      firtoolArgs:      Seq[String] = Seq.empty
    ): Seq[(Workspace, ElaboratedTest[T], ElaboratedModule[RawModule with SimulationTestHarnessInterface])] = {
      val updatedArgs = args ++ includeTestGlobs.map("--include-tests-name=" + _)
      val generated = generateWorkspaceSources(generateModule, updatedArgs, firtoolArgs)
      generated.testHarnesses.map { case elaboratedTest =>
        val testWorkspace = workspace.shallowCopy(workspace.absolutePath + "/tests/" + elaboratedTest.testName)
        val ports = getModuleInfoPorts(elaboratedTest.testHarness)
        val moduleInfo = testWorkspace.initializeModuleInfo(elaboratedTest.testHarness, ports.map(_._2))
        val layers = generated.outputAnnotations.collectFirst { case DesignAnnotation(_, layers) => layers }.get
        (
          testWorkspace,
          elaboratedTest,
          new ElaboratedModule(
            elaboratedTest.testHarness.asInstanceOf[RawModule with SimulationTestHarnessInterface],
            ports,
            layers
          )
        )
      }
    }

    case class GeneratedWorkspaceInfo[T <: RawModule](
      dut:               T,
      testHarnesses:     Seq[ElaboratedTest[T]],
      outputAnnotations: AnnotationSeq
    )

    /** Use CIRCT to generate SystemVerilog sources, and potentially additional artifacts */
    def generateWorkspaceSources[T <: RawModule](
      generateModule: () => T,
      args:           Seq[String],
      firtoolArgs:    Seq[String]
    ): GeneratedWorkspaceInfo[T] = {
      var someDut:           Option[() => T] = None
      var someTestHarnesses: Option[() => Seq[ElaboratedTest[T]]] = None
      val chiselArgs = Array("--target", "systemverilog", "--split-verilog") ++ args
      val outputAnnotations = (new circt.stage.ChiselStage).execute(
        chiselArgs,
        Seq(
          chisel3.stage.ChiselGeneratorAnnotation { () =>
            val dut = generateModule()
            someDut = Some(() => dut)
            someTestHarnesses = Some(() =>
              dut match {
                case dut: HasTests => dut.getElaboratedTests.map(_.asInstanceOf[ElaboratedTest[T]])
                case _ => Nil
              }
            )
            dut
          },
          circt.stage.FirtoolOption("-disable-annotation-unknown"),
          firrtl.options.TargetDirAnnotation(workspace.supportArtifactsPath)
        ) ++ firtoolArgs.map(circt.stage.FirtoolOption(_))
      )

      // Move the files indicated by a filelist.  No-op if the file has already
      // been moved.
      val movedFiles = mutable.HashSet.empty[Path]
      val supportArtifactsPath = Paths.get(workspace.supportArtifactsPath)
      def moveFile(file: Path): Unit = {
        // Convert the files to an absolute version and a relative version.
        val (_abs, rel) = file match {
          case file if file.startsWith(supportArtifactsPath) =>
            (file, file.subpath(supportArtifactsPath.getNameCount(), file.getNameCount()))
          case file => (supportArtifactsPath.resolve(file), file)
        }
        // Normalize the absolute path so it can be checked if it has already
        // been moved.
        val abs = _abs.normalize()
        // Move the file into primarySourcesPath if it has not already been moved.
        (abs, rel) match {
          case (abs, _) if movedFiles.contains(abs) =>
          case (abs, rel) =>
            val dest = Paths.get(workspace.primarySourcesPath).resolve(rel)
            dest.getParent.toFile.mkdirs
            Files.move(abs, dest)
            movedFiles += abs
        }
      }

      // Move all files from the build flow that have file extensions that
      // should be included:
      //   - Verilog files: .v, .sv, .vh, .svh
      //   - C++ files: .cc, .cpp, .h
      val includedExtensions = Set("v", "sv", "vh", "svh", "cc", "cpp", "h")
      Files
        .walk(supportArtifactsPath)
        .filter(_.toFile.isFile)
        .filter { f =>
          val filename = f.getFileName.toString
          val dotIndex = filename.lastIndexOf('.')
          dotIndex >= 0 && includedExtensions.contains(filename.substring(dotIndex + 1))
        }
        .forEach(moveFile)

      GeneratedWorkspaceInfo(
        someDut.get(),
        someTestHarnesses.get(),
        outputAnnotations
      )
    }

    def getModuleInfoPorts(dut: RawModule): Seq[(Data, ModuleInfo.Port)] = {

      /**
          * We infer the names of various ports since we don't currently have a good alternative when using MFC. We hope to replace this once we get better support from CIRCT.
          */
      def leafPorts(node: Data, name: String): Seq[(Data, ModuleInfo.Port)] = {
        node match {
          case record: Record => {
            record.elements.toSeq.flatMap { case (fieldName, field) =>
              leafPorts(field, s"${name}_${fieldName}")
            }
          }
          case vec: Vec[_] => {
            vec.zipWithIndex.flatMap { case (element, index) =>
              leafPorts(element, s"${name}_${index}")
            }
          }
          case element: Element =>
            // Return the port only if the width is positive (firtool will optimized it out from the *.sv primary source)
            if (element.widthKnown && element.getWidth > 0) {
              DataMirror.directionOf(element) match {
                case ActualDirection.Input =>
                  Seq((element, ModuleInfo.Port(name, isGettable = true, isSettable = true)))
                case ActualDirection.Output => Seq((element, ModuleInfo.Port(name, isGettable = true)))
                case _                      => Seq()
              }
            } else {
              Seq()
            }
        }
      }
      // Chisel ports can be Data or Property, but there is no ABI for Property ports, so we only return Data.
      DataMirror.modulePorts(dut).flatMap {
        case (name, data: Data) => leafPorts(data, name)
        case _                  => Nil
      }
    }

    def initializeModuleInfo(dut: RawModule, ports: Seq[ModuleInfo.Port]): Unit = {
      val info = ModuleInfo(
        name = dut.name,
        ports = ports
      )
      workspace.elaborate(info)
    }
  }
}

