29	    conservativeCommandResolution: Boolean = false,
30	    verbose:                       Boolean = false,
31	    traceEnabled:                  Boolean = false,
32	    executionScriptLimit:          Option[Int] = None
33	  )(body: Simulation.Controller => T): T = {
34	    val cwd = settings.customWorkingDirectory match {
35	      case None => workingDirectory
36	      case Some(value) =>
37	        val p = Paths.get(value)
38	        if (p.isAbsolute)
39	          p
40	        else
41	          workingDirectory.resolve(p)
42	    }
