46	    processBuilder.redirectError(ProcessBuilder.Redirect.INHERIT)
47	    val environment = settings.environment ++ Seq(
48	      Some("SVSIM_EXECUTION_SCRIPT" -> executionScriptPath),
49	      executionScriptLimit.map("SVSIM_EXECUTION_SCRIPT_LIMIT" -> _.toString)
