52	      processBuilder.environment().put(pair._1, pair._2)
53	    }
54	    val process = processBuilder.start()
55	    sys.addShutdownHook {
56	      if (process.isAlive())
57	        process.destroyForcibly()
58	    }
59	    val controller = new Simulation.Controller(
60	      new BufferedWriter(new OutputStreamWriter(process.getOutputStream())),
61	      new BufferedReader(new InputStreamReader(process.getInputStream())),
62	      moduleInfo,
63	      conservativeCommandResolution = conservativeCommandResolution,
64	      logMessagesAndCommands = verbose
65	    )
