115	object Simulation {
116	  private[svsim] final case class Settings(
117	    customWorkingDirectory: Option[String] = None,
118	    arguments:              Seq[String] = Seq(),
119	    environment:            Map[String, String] = Map()
120	  )
121	
122	  /** @note Methods in this class and `Simulation.Port` are somewhat lazy in their execution. Specifically, methods returning `Unit` neither flush the command buffer, nor do they actively read from the message buffer. Only commands which return a value will wait to return until the simulation has progressed to the point where the value is available. This can improve performance by essentially enabling batching of both commands and messages. If you want to ensure that all commands have been sent to the simulation executable, you can call `completeInFlightCommands()`.
123	    */
124	  final class Controller private[Simulation] (
125	    commandWriter:                 BufferedWriter,
126	    messageReader:                 BufferedReader,
127	    moduleInfo:                    ModuleInfo,
128	    conservativeCommandResolution: Boolean = false,
129	    logMessagesAndCommands:        Boolean = false
130	  ) {
131	
132	    private def readStringOfLength(length: Int): String = {
133	      val array = new Array[Char](length)
134	      val readLength = messageReader.read(array)
135	      if (readLength != length) {
136	        throw new Exception(s"Expected string of length ${length} but got ${readLength}")
137	      }
138	      new String(array)
139	    }
140	
141	    private var readMessageCount = 0
142	    // For specific message formats, consult `simulation-driver.cpp`
143	    private def readNextAvailableMessage(): Simulation.Message = {
144	      object MessageCode {
145	        val Ready = 'r'
146	        val Error = 'e'
147	        val Ack = 'k'
148	        val Bits = 'b'
149	        val Log = 'l'
150	      }
151	
152	      def readChar(): Option[Char] = {
153	        val array = new Array[Char](1)
154	        val read = messageReader.read(array)
155	        if (read != 1) {
156	          None
157	        } else {
158	          Some(array(0))
159	        }
160	      }
161	
162	      val messageCode = readChar() match {
163	        case Some(c) => c
164	        case None    => throw Simulation.UnexpectedEndOfMessages
165	      }
166	
167	      def mustRead(char: Char) = {
168	        val nextChar = readChar()
169	        if (nextChar != Some(char)) {
170	          throw new Exception(s"Expected '${char}' but got '${messageReader.readLine()}'")
171	        }
172	      }
173	      mustRead(' ')
174	
175	      import Simulation.Message._
176	      val message: Message = messageCode match {
177	        case MessageCode.Ready => {
178	          val rest = messageReader.readLine()
179	          if (rest != "ready") {
180	            throw new Exception(s"Malformed ready message: ${messageCode} ${rest}")
181	          }
182	          Ready
183	        }
184	        case MessageCode.Error => {
185	          throw new Error(messageReader.readLine())
186	        }
187	        case MessageCode.Ack => {
188	          val rest = messageReader.readLine()
189	          if (rest != "ack") {
190	            throw new Exception(s"Malformed ack message: ${messageCode} ${rest}")
191	          }
192	          Ack
193	        }
194	        case MessageCode.Bits => {
195	          val bitCount = Integer.parseInt(readStringOfLength(8), 16)
196	          mustRead(' ')
197	          Bits(bitCount, BigInt(messageReader.readLine(), 16))
198	        }
199	        case MessageCode.Log => {
200	          val length = Integer.parseInt(readStringOfLength(8), 16)
201	          if (length < 0) {
202	            throw new Exception("Invalid log message length")
203	          }
204	          mustRead(' ')
205	          val content = readStringOfLength(length)
206	          mustRead('\n')
207	          Log(new String(content))
208	        }
209	        case _ => throw new Exception(s"Unknown message code: ${messageCode}")
210	      }
211	      if (logMessagesAndCommands) {
212	        // NOTE: Commands are 1-indexed, but messages are 0-indexed since we read the first message (READY) before we send any commands.
213	        println(s"Received message ${readMessageCount}: ${message}")
214	      }
215	      readMessageCount += 1
216	      message
217	    }
218	
219	    private val expectations: Queue[PartialFunction[Simulation.Message, Unit]] = Queue.empty
220	
221	    def completeInFlightCommands() = {
222	      commandWriter.flush()
223	
224	      expectations.foreach { f =>
225	        val message = readNextAvailableMessage()
226	        if (f.isDefinedAt(message)) {
227	          f(message)
228	        } else {
229	          throw new Exception(s"Unexpected message: ${message}")
230	        }
231	      }
232	      expectations.clear()
233	    }
234	
235	    private[Simulation] def processNextMessage[A](f: PartialFunction[Simulation.Message, A]): A = {
236	      completeInFlightCommands()
237	
238	      val message = readNextAvailableMessage()
239	      if (f.isDefinedAt(message)) {
240	        f(message)
241	      } else {
242	        throw new Exception(s"Unexpected message: ${message}")
243	      }
244	    }
245	
246	    private[Simulation] def expectNextMessage(f: PartialFunction[Simulation.Message, Unit]) = {
247	      // If expectations queue are more than 1000 deep, we force processing to avoid deadlock.
248	      // See: https://github.com/chipsalliance/chisel/issues/5128
249	      if (conservativeCommandResolution || expectations.size > 1000) {
250	        processNextMessage(f)
251	      } else {
252	        expectations.enqueue(f)
253	      }
254	    }
255	
256	    private var sentCommandCount = 0
257	    private[Simulation] def sendCommand(command: Simulation.Command) = {
258	      object CommandCode extends Enumeration {
259	        val Done = 'D'
260	        val Log = 'L'
261	        val GetBits = 'G'
262	        val SetBits = 'S'
263	        val Run = 'R'
264	        val Tick = 'T'
265	        val Trace = 'W'
266	      };
267	
268	      sentCommandCount += 1
269	      if (logMessagesAndCommands) {
270	        // NOTE: Commands are 1-indexed, but messages are 0-indexed since we read the first message (READY) before we send any commands.
271	        println(s"Sending command ${sentCommandCount}: ${command}")
272	      }
273	
274	      import Simulation.Command._
275	      // For specific command formats, consult `simulation-driver.cpp`
276	      command match {
277	        case Done => {
278	          commandWriter.write(CommandCode.Done)
279	        }
280	        case Log => {
281	          commandWriter.write(CommandCode.Log)
282	        }
283	        case GetBits(id, isSigned) => {
284	          commandWriter.write(CommandCode.GetBits)
285	          commandWriter.write(" ")
286	          commandWriter.write(if (isSigned) "s" else "u")
287	          commandWriter.write(" ")
288	          commandWriter.write(id)
289	        }
290	        case SetBits(id, value) => {
291	          commandWriter.write(CommandCode.SetBits)
292	          commandWriter.write(" ")
293	          commandWriter.write(id)
294	          commandWriter.write(" ")
295	          commandWriter.write(value.toString(16))
296	        }
297	        case Run(timesteps) => {
298	          commandWriter.write(CommandCode.Run)
299	          commandWriter.write(" ")
300	          commandWriter.write(timesteps.toHexString)
301	        }
302	        case Tick(id, inPhaseValue, outOfPhaseValue, timestepsPerPhase, maxCycles, sentinel) => {
303	          commandWriter.write(CommandCode.Tick)
304	          commandWriter.write(" ")
305	          commandWriter.write(id)
306	          commandWriter.write(" ")
307	          commandWriter.write(inPhaseValue.toString(16))
308	          commandWriter.write(",")
309	          commandWriter.write(outOfPhaseValue.toString(16))
310	          commandWriter.write("-")
311	          commandWriter.write(timestepsPerPhase.toHexString)
312	          commandWriter.write("*")
313	          commandWriter.write(maxCycles.toHexString)
314	          sentinel match {
315	            case Some((port, value)) => {
316	              commandWriter.write(" ")
317	              commandWriter.write(port.id)
318	              commandWriter.write("=")
319	              commandWriter.write(value.toString(16))
320	            }
321	            case None =>
322	          }
323	        }
324	        case Trace(enable) => {
325	          commandWriter.write(CommandCode.Trace)
326	          commandWriter.write(" ")
327	          commandWriter.write(if (enable) "1" else "0")
328	        }
329	      }
330	      commandWriter.newLine()
331	    }
332	
333	    def readLog(): String = {
334	      sendCommand(Simulation.Command.Log)
335	      processNextMessage { case Simulation.Message.Log(message) =>
336	        message
337	      }
338	    }
339	
340	    def run(timesteps: Int) = {
341	      sendCommand(Simulation.Command.Run(timesteps))
342	      expectNextMessage { case Simulation.Message.Ack => }
343	    }
344	
345	    def setTraceEnabled(enabled: Boolean): Unit = {
346	      sendCommand(Simulation.Command.Trace(enabled))
347	      expectNextMessage { case Simulation.Message.Ack => }
348	    }
349	
350	    private val portInfos = moduleInfo.ports.zipWithIndex.map { case (port, index) =>
351	      port.name -> (index.toHexString, port)
352	    }.toMap
353	
354	    def port(name: String): Simulation.Port = {
355	      val (id, info) = portInfos.get(name).get
356	      new Simulation.Port(this, id, info)
357	    }
358	
359	    // Simulation starts with a single `READY` message
360	    expectNextMessage { case Simulation.Message.Ready => }
361	  }
362	
363	  sealed trait Message
364	  object Message {
365	    case object Ready extends Message
366	    case object Ack extends Message
367	    case class Error(message: String) extends Throwable(message) with Message
368	    case class Bits(count: Int, value: BigInt) extends Message
369	    case class Log(message: String) extends Message
370	  }
371	
372	  case object UnexpectedEndOfMessages extends Exception
373	
374	  sealed trait Command
375	  object Command {
376	    case object Done extends Command
377	    case object Log extends Command
378	    case class GetBits(id: String, isSigned: Boolean) extends Command
379	    case class SetBits(id: String, value: BigInt) extends Command
380	    case class Run(timesteps: Int) extends Command
381	    case class Tick(
382	      id:                String,
383	      inPhaseValue:      BigInt,
384	      outOfPhaseValue:   BigInt,
385	      timestepsPerPhase: Int,
386	      maxCycles:         Int,
387	      sentinel:          Option[(Port, BigInt)]
388	    ) extends Command
389	    case class Trace(enable: Boolean) extends Command
390	  }
391	
392	  final case class Value(bitCount: Int, asBigInt: BigInt)
393	
394	  final case class Port private[Simulation] (controller: Simulation.Controller, id: String, info: ModuleInfo.Port) {
395	
396	    def set(value: BigInt) = {
397	      require(
398	        info.isSettable,
399	        s"cannot set port '${info.name}' (id: '$id') because it is not settable.  (Did you try to poke an output port?)"
400	      )
401	      controller.sendCommand(Simulation.Command.SetBits(id, value))
402	      controller.expectNextMessage { case Simulation.Message.Ack =>
403	      }
404	    }
405	
406	    def get(isSigned: Boolean = false): Value = {
407	      require(
408	        info.isGettable,
409	        s"cannot get port '${info.name}' (id: '$id') because it is not gettable"
410	      )
411	      controller.sendCommand(Simulation.Command.GetBits(id, isSigned))
412	      controller.processNextMessage { case Simulation.Message.Bits(bitCount, value) =>
413	        Value(bitCount, value)
414	      }
415	    }
416	
417	    def tick(timestepsPerPhase: Int, cycles: Int, inPhaseValue: BigInt, outOfPhaseValue: BigInt) = {
418	      controller.sendCommand(
419	        Simulation.Command.Tick(id, inPhaseValue, outOfPhaseValue, timestepsPerPhase, cycles, None)
420	      )
421	      controller.expectNextMessage { case Simulation.Message.Bits(_, _) =>
422	      }
423	    }
424	
425	    def tick(
426	      timestepsPerPhase: Int,
427	      maxCycles:         Int,
428	      inPhaseValue:      BigInt,
429	      outOfPhaseValue:   BigInt,
430	      sentinel:          Option[(Port, BigInt)]
431	    ): BigInt = {
432	      controller.sendCommand(
433	        Simulation.Command.Tick(id, inPhaseValue, outOfPhaseValue, timestepsPerPhase, maxCycles, sentinel)
434	      )
435	      controller.processNextMessage { case Simulation.Message.Bits(_, cyclesElapsed) =>
436	        cyclesElapsed
437	      }
438	    }
439	
440	    def tick(
441	      timestepsPerPhase:      Int,
442	      maxCycles:              Int,
443	      inPhaseValue:           BigInt,
444	      outOfPhaseValue:        BigInt,
445	      sentinel:               Option[(Port, BigInt)],
446	      checkElapsedCycleCount: (BigInt) => Unit
447	    ) = {
448	      controller.sendCommand(
449	        Simulation.Command.Tick(id, inPhaseValue, outOfPhaseValue, timestepsPerPhase, maxCycles, sentinel)
450	      )
451	      controller.expectNextMessage { case Simulation.Message.Bits(_, cyclesElapsed) =>
452	        checkElapsedCycleCount(cyclesElapsed)
453	      }
454	    }
455	
456	    def check(f: Value => Unit): Unit = check()(f)
457	    def check(isSigned: Boolean = false)(f: Value => Unit): Unit = {
458	      controller.sendCommand(Simulation.Command.GetBits(id, isSigned))
459	      controller.expectNextMessage { case Simulation.Message.Bits(bitCount, value) =>
460	        f(Value(bitCount, value))
461	      }
462	    }
463	  }
464	}
